const body = $('Webhook').first().json.body || {};
const { issue_id } = body;
if (!issue_id) throw new Error('MISSING_ISSUE_ID');

const issues = $input.all().map(x => x.json);
const issue = issues.find(i => i.issue_id === issue_id);
if (!issue) throw new Error('ISSUE_NOT_FOUND');

const systemPrompt = `You are a helpdesk triage assistant for a car-refurbishment workshop operations team.
Your job: given a technician-submitted issue, output a JSON object with exactly these fields:
{
  "priority": "critical" | "high" | "medium" | "low",
  "category": "equipment" | "parts" | "software" | "safety" | "hr" | "other",
  "triage_note": "<2-3 sentence summary of the issue and recommended action>",
  "suggested_assignee_role": "admin" | "manager" | null
}
Respond with raw JSON only — no markdown, no extra text.`;

const userPrompt = `Issue ID: ${issue.issue_id}
Title: ${issue.title}
Description: ${issue.description || '(none)'}
Workshop: ${issue.workshop_id}
Current priority: ${issue.priority}
Current category: ${issue.category}`;

return [{ json: { issue, systemPrompt, userPrompt } }];

const aiRaw = $input.first().json;
const issue  = $('Build prompt').first().json.issue;

// Flexibly extract text from various AI response shapes
const text = aiRaw.text || aiRaw.output || aiRaw.response || aiRaw.content || aiRaw.message || JSON.stringify(aiRaw);

let parsed;
try {
  // Strip markdown code fences if present
  const cleaned = String(text).replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: don't crash, just keep existing values
  parsed = {};
}

const validPriority   = ['critical', 'high', 'medium', 'low'];
const validCategories = ['equipment', 'parts', 'software', 'safety', 'hr', 'other'];

const priority    = validPriority.includes(parsed.priority)   ? parsed.priority   : issue.priority;
const category    = validCategories.includes(parsed.category) ? parsed.category   : issue.category;
const triage_note = parsed.triage_note ? String(parsed.triage_note).slice(0, 1000) : '';

return [{ json: {
  issue_id:        issue.issue_id,
  priority,
  category,
  ai_triage_note:  triage_note,
  updated_at:      new Date().toISOString(),
} }];
